// src/event/Event.js
import React, { useState, useEffect } from 'react';
import './Event.css'; // スタイルシートのインポート

const Event = () => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: 'draft', event_info: '' });

  // イベントリストを取得する
  const fetchEvents = async () => {
    const response = await fetch('http://localhost:8000/event/get');
    const data = await response.json();
    setEvents(data);
  };

  // コンポーネントのマウント時にイベントリストを取得
  useEffect(() => {
    fetchEvents();
  }, []);

  // 新しいイベントを登録する
  const registerEvent = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:8000/event/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newEvent)
    });
    setNewEvent({ event_name: '', event_state: 'draft', event_info: '' });
    fetchEvents(); // リストを更新
  };

  // イベントを更新する
  const updateEvent = async (eventToUpdate) => {
    await fetch(`http://localhost:8000/event/edit/${eventToUpdate.event_id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(eventToUpdate)
    });
    fetchEvents(); // リストを更新
  };

  // イベントを削除する
  const deleteEvent = async (eventId) => {
    await fetch(`http://localhost:8000/event/delete/${eventId}`, { method: 'DELETE' });
    fetchEvents(); // リストを更新
  };

  return (
    <div>
      <div className="event-container">
        <div className="event-registration">
          <h2>イベント登録</h2>
          <form onSubmit={registerEvent}>
            <input
              type="text"
              value={newEvent.event_name}
              onChange={(e) => setNewEvent({ ...newEvent, event_name: e.target.value })}
              placeholder="イベント名"
              required
            />
            <select
              value={newEvent.event_state}
              onChange={(e) => setNewEvent({ ...newEvent, event_state: e.target.value })}
              required
            >
              <option value="draft">下書き</option>
              <option value="open">公開中</option>
              <option value="close">終了</option>
            </select>
            <input
              type="text"
              value={newEvent.event_info} // 新しいstateプロパティ
              onChange={(e) => setNewEvent({ ...newEvent, event_info: e.target.value })}
              placeholder="イベント情報"
              required
            />
            <button type="submit">登録</button>
          </form>
        </div>
        <div className="event-list">
          <h2>イベント一覧/編集</h2>
          {events.map((event) => (
            <div key={event.event_id} className="event-item">
              <input
                type="text"
                value={event.event_name}
                onChange={(e) => setEvents(events.map(ev => ev.event_id === event.event_id ? { ...ev, event_name: e.target.value } : ev))}
              />
              <select
                value={event.event_state}
                onChange={(e) => setEvents(events.map(ev => ev.event_id === event.event_id ? { ...ev, event_state: e.target.value } : ev))}
              >
                <option value="draft">下書き</option>
                <option value="open">公開中</option>
                <option value="close">終了</option>
              </select>
              <input
                type="text"
                value={event.event_info} // 新しいstateプロパティ
                onChange={(e) => setEvents(events.map(ev => ev.event_id === event.event_id ? { ...ev, event_info: e.target.value } : ev))}
              />
              <button onClick={() => updateEvent(event)}>更新</button>
              <button onClick={() => deleteEvent(event.event_id)}>削除</button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Event;
